INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('html-1', 'html-basics', 'Что такое HTML?', 'Знакомство с HTML', 15, 'HTML (HyperText Markup Language) — язык разметки. Браузер читает HTML и строит из него страницу: заголовки, абзацы, кнопки.

Каждый фрагмент контента оборачивается в теги: <тег>содержимое</тег>. Теги не «рисуют» дизайн — они описывают смысл: «это заголовок», «это ссылка».

Базовый каркас документа:
<!DOCTYPE html>
<html>
  <head><title>Заголовок вкладки</title></head>
  <body>Здесь видимый контент</body>
</html>

Параграф — тег <p>. На практике ты соберёшь простую разметку и проверишь, что браузер понимает структуру.', '[{"id":"html-1-1","type":"quiz","question":"Что означает HTML?","options":["HyperText Markup Language","High Tech Modern Language","Home Tool Markup Language","Hyper Transfer Markup Language"],"correctAnswer":"HyperText Markup Language"},{"id":"html-1-2","type":"quiz","question":"Какой тег используется для параграфа?","options":["<p>","<div>","<span>","<text>"],"correctAnswer":"<p>"},{"id":"html-1-3","type":"blocks","question":"Собери HTML-элемент параграфа с текстом ''Привет''","blocks":["</p>","Привет","<p>"],"correctOrder":["<p>","Привет","</p>"]},{"id":"html-1-4","type":"match","question":"Соедини HTML-тег с его назначением","pairs":[{"left":"<p>","right":"Параграф"},{"left":"<h1>","right":"Главный заголовок"},{"left":"<a>","right":"Ссылка"}]}]'::jsonb, '[{"id":"html-1-intro-1","speaker":"falstaff","text":"Привет! Я Фальстаф, твой проводник в мир HTML.","emotion":"happy"},{"id":"html-1-intro-2","speaker":"falstaff","text":"Сегодня узнаем, что такое теги и зачем они нужны.","emotion":"think"}]'::jsonb, '[{"id":"html-1-outro-1","speaker":"falstaff","text":"Отлично! Ты освоил основы HTML.","emotion":"happy"},{"id":"html-1-outro-2","speaker":"falstaff","text":"Впереди ещё много приключений в коде!","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Лаборатория Фальстафа","subtitle":"Нажми на объекты и закрепи урок","background":"room","hotspots":[{"id":"html-1-spot-1","label":"Тег","x":0.22,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"m1","type":"quiz","question":"HTML — это язык…","options":["разметки","программирования"],"correctAnswer":"разметки"},"doneLabel":"Готово"},{"id":"html-1-spot-2","label":"Книга","x":0.5,"y":0.42,"width":0.16,"height":0.14,"task":{"id":"m2","type":"quiz","question":"Параграф создаёт тег…","options":["<p>","<div>"],"correctAnswer":"<p>"},"doneLabel":"Готово"},{"id":"html-1-spot-3","label":"Дверь","x":0.78,"y":0.58,"width":0.16,"height":0.14,"task":{"id":"m3","type":"blocks","question":"Собери <p>Привет</p>","blocks":["<p>","Привет","</p>"],"correctOrder":["<p>","Привет","</p>"]},"doneLabel":"Готово"}]}'::jsonb, 0) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('html-2', 'html-basics', 'Теги и элементы', 'Открывающие и закрывающие теги', 20, 'Элемент = открывающий тег + содержимое + закрывающий тег. Пример: <p>Текст</p>.

Вложенность важна: внутренний элемент закрывают раньше внешнего. Неправильная вложенность ломает разметку.

Самозакрывающиеся теги не имеют пары: <br> (перенос строки), <hr> (линия), <img src="..." alt="...">.

Атрибуты дополняют тег: <a href="/about">О нас</a>. Кавычки в значениях обязательны, если внутри есть пробелы.

После теории — задания на сборку тегов и исправление типичных ошибок.', '[{"id":"html-2-1","type":"quiz","question":"Какой тег является самозакрывающимся?","options":["<br>","<p>","<div>","<span>"],"correctAnswer":"<br>"},{"id":"html-2-2","type":"debug","question":"Найди и исправь ошибку в HTML-коде","buggyCode":"<h1>Заголовок<h1>","fixedCode":"<h1>Заголовок</h1>"},{"id":"html-2-3","type":"blocks","question":"Собери заголовок h1 с текстом ''Мой сайт''","blocks":["</h1>","<h1>","Мой сайт"],"correctOrder":["<h1>","Мой сайт","</h1>"]}]'::jsonb, '[{"id":"html-2-intro-1","speaker":"falstaff","text":"Я Фальстаф. Сейчас разберём теорию урока «Теги и элементы».","emotion":"happy"},{"id":"html-2-intro-2","speaker":"falstaff","text":"Открывающие и закрывающие теги","emotion":"think"}]'::jsonb, '[{"id":"html-2-outro-1","speaker":"falstaff","text":"Урок «Теги и элементы» пройден. Молодец!","emotion":"happy"},{"id":"html-2-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Теги и элементы","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"html-2-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"html-2-ma","type":"quiz","question":"Какой тег является самозакрывающимся?","options":["<br>","<p>","<div>","<span>"],"correctAnswer":"<br>"},"doneLabel":"Готово"},{"id":"html-2-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"html-2-mb","type":"quiz","question":"Повтор: Теги и элементы?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"html-2-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"html-2-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 1) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('html-3', 'html-basics', 'Заголовки', 'Теги h1–h6', 20, 'Заголовки задают иерархию: <h1> … <h6>. <h1> — главный заголовок страницы (обычно один).

<h2> — разделы, <h3> — подразделы. Не прыгай с <h1> сразу на <h4>: так хуже и для людей, и для поисковиков.

Заголовки не для «крупного текста» — для структуры. Размер шрифта потом настроит CSS.

Практика: выбери правильный уровень заголовка и собери мини-оглавление статьи.', '[{"id":"html-3-1","type":"quiz","question":"Какой заголовок самый важный?","options":["<h1>","<h6>","<h3>","<header>"],"correctAnswer":"<h1>"},{"id":"html-3-2","type":"code","question":"Напиши заголовок второго уровня с текстом ''Обо мне''","starterCode":"","expectedOutput":"<h2>Обо мне</h2>","hint":"Используй тег <h2>"},{"id":"html-3-3","type":"blocks","question":"Расставь заголовки в правильном порядке по важности","blocks":["<h3>","<h1>","<h2>"],"correctOrder":["<h1>","<h2>","<h3>"]}]'::jsonb, '[{"id":"html-3-intro-1","speaker":"falstaff","text":"Я Фальстаф. Сейчас разберём теорию урока «Заголовки».","emotion":"happy"},{"id":"html-3-intro-2","speaker":"falstaff","text":"Теги h1–h6","emotion":"think"}]'::jsonb, '[{"id":"html-3-outro-1","speaker":"falstaff","text":"Урок «Заголовки» пройден. Молодец!","emotion":"happy"},{"id":"html-3-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Заголовки","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"html-3-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"html-3-ma","type":"quiz","question":"Какой заголовок самый важный?","options":["<h1>","<h6>","<h3>","<header>"],"correctAnswer":"<h1>"},"doneLabel":"Готово"},{"id":"html-3-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"html-3-mb","type":"quiz","question":"Повтор: Заголовки?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"html-3-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"html-3-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 2) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('html-4', 'html-basics', 'Ссылки и изображения', 'Теги <a> и <img>', 25, 'Ссылка: <a href="https://example.com">Текст</a>. href — адрес; можно относительный: href="/blog".

target="_blank" открывает в новой вкладке; для безопасности добавляют rel="noopener".

Изображение: <img src="photo.jpg" alt="Описание">. alt обязателен: его читают скринридеры и показывают, если картинка не загрузилась.

src — путь к файлу, alt — что изображено. На практике свяжешь ссылки и картинки с заданиями.', '[{"id":"html-4-1","type":"quiz","question":"Какой атрибут задаёт адрес ссылки?","options":["href","src","link","url"],"correctAnswer":"href"},{"id":"html-4-2","type":"quiz","question":"Какой атрибут <img> описывает картинку для скринридеров?","options":["alt","title","desc","label"],"correctAnswer":"alt"},{"id":"html-4-3","type":"blocks","question":"Собери тег ссылки на google.com","blocks":["</a>","Google","<a href=\"https://google.com\">"],"correctOrder":["<a href=\"https://google.com\">","Google","</a>"]},{"id":"html-4-4","type":"fill","question":"Заполни пропуски в ссылке","textParts":["<a ","=\"https://example.com\">","</a>"],"fillOptions":["href","src","Документация","Картинка"],"correctFill":["href","Документация"]}]'::jsonb, '[{"id":"html-4-intro-1","speaker":"falstaff","text":"Я Фальстаф. Сейчас разберём теорию урока «Ссылки и изображения».","emotion":"happy"},{"id":"html-4-intro-2","speaker":"falstaff","text":"Теги <a> и <img>","emotion":"think"}]'::jsonb, '[{"id":"html-4-outro-1","speaker":"falstaff","text":"Урок «Ссылки и изображения» пройден. Молодец!","emotion":"happy"},{"id":"html-4-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Ссылки и изображения","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"html-4-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"html-4-ma","type":"quiz","question":"Какой атрибут задаёт адрес ссылки?","options":["href","src","link","url"],"correctAnswer":"href"},"doneLabel":"Готово"},{"id":"html-4-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"html-4-mb","type":"quiz","question":"Повтор: Ссылки и изображения?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"html-4-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"html-4-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 3) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('html-5', 'html-basics', 'Списки', 'Нумерованные и маркированные', 25, 'Маркированный список (точки): <ul><li>Пункт</li></ul>.

Нумерованный (1, 2, 3): <ol><li>Шаг</li></ol>.

<li> всегда внутри <ul> или <ol>. Списки можно вкладывать для подпунктов.

Используй ul для перечислений без порядка, ol для инструкций и рейтингов. Дальше — задания на сборку списков из блоков.', '[{"id":"html-5-1","type":"quiz","question":"Какой тег создаёт маркированный список?","options":["<ul>","<ol>","<li>","<list>"],"correctAnswer":"<ul>"},{"id":"html-5-2","type":"debug","question":"Исправь ошибку в списке","buggyCode":"<ul><li>Один<li>Два</li></ul>","fixedCode":"<ul><li>Один</li><li>Два</li></ul>"},{"id":"html-5-3","type":"blocks","question":"Собери маркированный список из 2 элементов","blocks":["</ul>","<li>Два</li>","<ul>","<li>Один</li>"],"correctOrder":["<ul>","<li>Один</li>","<li>Два</li>","</ul>"]}]'::jsonb, '[{"id":"html-5-intro-1","speaker":"falstaff","text":"Я Фальстаф. Сейчас разберём теорию урока «Списки».","emotion":"happy"},{"id":"html-5-intro-2","speaker":"falstaff","text":"Нумерованные и маркированные","emotion":"think"}]'::jsonb, '[{"id":"html-5-outro-1","speaker":"falstaff","text":"Урок «Списки» пройден. Молодец!","emotion":"happy"},{"id":"html-5-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Списки","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"html-5-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"html-5-ma","type":"quiz","question":"Какой тег создаёт маркированный список?","options":["<ul>","<ol>","<li>","<list>"],"correctAnswer":"<ul>"},"doneLabel":"Готово"},{"id":"html-5-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"html-5-mb","type":"quiz","question":"Повтор: Списки?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"html-5-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"html-5-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 4) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('html-6', 'html-basics', 'Кнопки и формы', 'input, button, form', 30, 'Форма отправляет данные: <form action="/send" method="post">…</form>.

<input type="text" name="email" placeholder="Почта"> — поле ввода. type бывает email, password, number, checkbox.

<button type="submit">Отправить</button> — кнопка отправки. type="button" — просто клик без отправки.

label связывает подпись с полем: <label for="name">Имя</label><input id="name" name="name">. На практике соберёшь простую форму регистрации.', '[{"id":"html-6-1","type":"quiz","question":"Какой тег создаёт поле ввода?","options":["<input>","<button>","<label>","<textarea/>"],"correctAnswer":"<input>"},{"id":"html-6-2","type":"fill","question":"Заполни пропуски в кнопке отправки формы","textParts":["<button ","=\"submit\">","</button>"],"fillOptions":["type","href","Отправить","Картинка"],"correctFill":["type","Отправить"]},{"id":"html-6-3","type":"blocks","question":"Собери простую форму с одним полем","blocks":["</form>","<input type=\"text\">","<form>"],"correctOrder":["<form>","<input type=\"text\">","</form>"]},{"id":"html-6-4","type":"match","question":"Соедини тег формы с назначением","pairs":[{"left":"<form>","right":"Оборачивает элементы формы"},{"left":"<input>","right":"Поле ввода"},{"left":"<button>","right":"Кнопка действия"}]}]'::jsonb, '[{"id":"html-6-intro-1","speaker":"falstaff","text":"Я Фальстаф. Сейчас разберём теорию урока «Кнопки и формы».","emotion":"happy"},{"id":"html-6-intro-2","speaker":"falstaff","text":"input, button, form","emotion":"think"}]'::jsonb, '[{"id":"html-6-outro-1","speaker":"falstaff","text":"Урок «Кнопки и формы» пройден. Молодец!","emotion":"happy"},{"id":"html-6-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Кнопки и формы","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"html-6-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"html-6-ma","type":"quiz","question":"Какой тег создаёт поле ввода?","options":["<input>","<button>","<label>","<textarea/>"],"correctAnswer":"<input>"},"doneLabel":"Готово"},{"id":"html-6-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"html-6-mb","type":"quiz","question":"Повтор: Кнопки и формы?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"html-6-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"html-6-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 5) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('html-7', 'html-basics', 'Семантические теги', 'header, main, footer, nav', 30, 'Семантика — «осмысленные» теги вместо сплошных <motion.div>:
<header> шапка, <nav> меню, <main> основной контент, <article> статья, <section> раздел, <footer> подвал, <aside> боковая колонка.

Поисковики и доступность лучше понимают страницу. Код проще читать коллегам.

Типичная схема: header + nav + main (sections) + footer. Практика — разметить макет страницы семантическими блоками.', '[{"id":"html-7-1","type":"quiz","question":"Какой тег обычно содержит главное содержимое страницы?","options":["<main>","<footer>","<aside>","<title>"],"correctAnswer":"<main>"},{"id":"html-7-2","type":"match","question":"Соедини семантический тег и его роль","pairs":[{"left":"<header>","right":"Верхняя часть страницы"},{"left":"<nav>","right":"Блок навигации"},{"left":"<footer>","right":"Нижняя часть страницы"}]},{"id":"html-7-3","type":"debug","question":"Исправь ошибку в семантической разметке","buggyCode":"<main><h1>Статья</h2></main>","fixedCode":"<main><h1>Статья</h1></main>"},{"id":"html-7-4","type":"blocks","question":"Собери каркас страницы из семантических тегов","blocks":["<main></main>","<footer></footer>","<header></header>"],"correctOrder":["<header></header>","<main></main>","<footer></footer>"]}]'::jsonb, '[{"id":"html-7-intro-1","speaker":"falstaff","text":"Я Фальстаф. Сейчас разберём теорию урока «Семантические теги».","emotion":"happy"},{"id":"html-7-intro-2","speaker":"falstaff","text":"header, main, footer, nav","emotion":"think"}]'::jsonb, '[{"id":"html-7-outro-1","speaker":"falstaff","text":"Урок «Семантические теги» пройден. Молодец!","emotion":"happy"},{"id":"html-7-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Семантические теги","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"html-7-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"html-7-ma","type":"quiz","question":"Какой тег обычно содержит главное содержимое страницы?","options":["<main>","<footer>","<aside>","<title>"],"correctAnswer":"<main>"},"doneLabel":"Готово"},{"id":"html-7-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"html-7-mb","type":"quiz","question":"Повтор: Семантические теги?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"html-7-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"html-7-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 6) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
