INSERT INTO public.course_levels (id, course_id, title, sort_order) VALUES ('css-basics', 'css', 'Основы CSS', 0) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('css-1', 'css-basics', 'Что такое CSS?', 'Стилизация страниц', 15, 'CSS (Cascading Style Sheets) оформляет HTML. Правило: селектор { свойство: значение; }.

Подключение: <link rel="stylesheet" href="style.css"> или <style> в head.

Каскад: если несколько правил на один элемент, побеждает более специфичное или последнее.

Свойства: color, font-size, margin, padding. Единицы: px, %, rem. После теории — задания на селекторы и простые стили.', '[{"id":"css-1-1","type":"quiz","question":"Что означает CSS?","options":["Cascading Style Sheets","Creative Style System","Computer Style Sheets","Colorful Style Sheets"],"correctAnswer":"Cascading Style Sheets"},{"id":"css-1-2","type":"quiz","question":"Какое свойство задаёт цвет текста?","options":["color","text-color","font-color","foreground"],"correctAnswer":"color"},{"id":"css-1-3","type":"code","question":"Напиши CSS-правило, делающее текст красным","starterCode":"p { }","expectedOutput":"color: red;","hint":"Используй свойство color"}]'::jsonb, '[{"id":"css-1-intro-1","speaker":"falstaff","text":"Я Фальстаф. Сейчас разберём теорию урока «Что такое CSS?».","emotion":"happy"},{"id":"css-1-intro-2","speaker":"falstaff","text":"Стилизация страниц","emotion":"think"}]'::jsonb, '[{"id":"css-1-outro-1","speaker":"falstaff","text":"Урок «Что такое CSS?» пройден. Молодец!","emotion":"happy"},{"id":"css-1-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Что такое CSS?","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"css-1-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"css-1-ma","type":"quiz","question":"Что означает CSS?","options":["Cascading Style Sheets","Creative Style System","Computer Style Sheets","Colorful Style Sheets"],"correctAnswer":"Cascading Style Sheets"},"doneLabel":"Готово"},{"id":"css-1-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"css-1-mb","type":"quiz","question":"Повтор: Что такое CSS??","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"css-1-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"css-1-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 0) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('css-2', 'css-basics', 'Селекторы', 'Классы и ID', 20, 'Селектор по тегу: p { color: blue; } — все абзацы.

По классу: .card { border: 1px solid #ccc; } — элементы class="card".

По id: #logo { width: 120px; } — один элемент id="logo" на странице.

Комбинаторы: .menu a — ссылка внутри .menu. :hover меняет стиль при наведении.

Специфичность: id > class > тег. Практика — применить селекторы к разметке урока.', '[{"id":"css-2-1","type":"quiz","question":"Как обратиться к элементу с классом ''title''?","options":[".title","#title","title","@title"],"correctAnswer":".title"},{"id":"css-2-2","type":"quiz","question":"Какой символ используется для ID-селектора?","options":["#",".","@","&"],"correctAnswer":"#"},{"id":"css-2-3","type":"blocks","question":"Собери CSS-правило для класса ''btn''","blocks":["}","background: blue;",".btn {"],"correctOrder":[".btn {","background: blue;","}"]},{"id":"css-2-4","type":"match","question":"Соедини селектор с тем, что он выбирает","pairs":[{"left":".card","right":"Элемент с классом"},{"left":"#header","right":"Элемент с ID"},{"left":"p","right":"Все теги параграфа"}]}]'::jsonb, '[{"id":"css-2-intro-1","speaker":"falstaff","text":"Я Фальстаф. Сейчас разберём теорию урока «Селекторы».","emotion":"happy"},{"id":"css-2-intro-2","speaker":"falstaff","text":"Классы и ID","emotion":"think"}]'::jsonb, '[{"id":"css-2-outro-1","speaker":"falstaff","text":"Урок «Селекторы» пройден. Молодец!","emotion":"happy"},{"id":"css-2-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Селекторы","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"css-2-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"css-2-ma","type":"quiz","question":"Как обратиться к элементу с классом ''title''?","options":[".title","#title","title","@title"],"correctAnswer":".title"},"doneLabel":"Готово"},{"id":"css-2-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"css-2-mb","type":"quiz","question":"Повтор: Селекторы?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"css-2-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"css-2-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 1) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('css-3', 'css-basics', 'Размеры и отступы', 'margin, padding, width, height', 20, 'Блочная модель: content → padding → border → margin.

margin — отступ снаружи, padding — внутри до границы контента.

width / height задают размер содержимого (не всего блока с padding). box-sizing: border-box включает padding в width.

Единицы: px — пиксели, % — от родителя, em/rem — от размера шрифта. rem удобен для единообразия. Дальше — задачи на отступы и размеры.', '[{"id":"css-3-1","type":"quiz","question":"Какое свойство задаёт внутренний отступ?","options":["padding","margin","spacing","indent"],"correctAnswer":"padding"},{"id":"css-3-2","type":"code","question":"Задай элементу внешний отступ 20px со всех сторон","starterCode":".box { }","expectedOutput":"margin: 20px;","hint":"Используй свойство margin"},{"id":"css-3-3","type":"debug","question":"Исправь ошибку в CSS","buggyCode":".box { maring: 10px; }","fixedCode":".box { margin: 10px; }"},{"id":"css-3-4","type":"fill","question":"Вставь нужные свойства в CSS-правило","textParts":[".box { ",": 12px; ",": 24px; }"],"fillOptions":["padding","margin","display","color"],"correctFill":["padding","margin"]}]'::jsonb, '[{"id":"css-3-intro-1","speaker":"falstaff","text":"Я Фальстаф. Сейчас разберём теорию урока «Размеры и отступы».","emotion":"happy"},{"id":"css-3-intro-2","speaker":"falstaff","text":"margin, padding, width, height","emotion":"think"}]'::jsonb, '[{"id":"css-3-outro-1","speaker":"falstaff","text":"Урок «Размеры и отступы» пройден. Молодец!","emotion":"happy"},{"id":"css-3-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Размеры и отступы","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"css-3-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"css-3-ma","type":"quiz","question":"Какое свойство задаёт внутренний отступ?","options":["padding","margin","spacing","indent"],"correctAnswer":"padding"},"doneLabel":"Готово"},{"id":"css-3-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"css-3-mb","type":"quiz","question":"Повтор: Размеры и отступы?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"css-3-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"css-3-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 2) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('css-4', 'css-basics', 'Цвета и фон', 'color, background, hex', 25, 'color — цвет текста, background-color — фон блока.

Форматы: имя (red), hex (#ff5733), rgb(255, 87, 51), rgba(…, 0.5) с прозрачностью.

Контраст текста и фона важен для читаемости. Светлый текст на тёмном фоне — классика тёмной темы.

background-image: url(''bg.png''); background-size: cover; — фоновая картинка. Практика — раскрасить карточки и кнопки.', '[{"id":"css-4-1","type":"quiz","question":"Какое свойство меняет фон элемента?","options":["background-color","font-color","bg","fill"],"correctAnswer":"background-color"},{"id":"css-4-2","type":"code","question":"Сделай фон блока синим","starterCode":".card { }","expectedOutput":"background-color: blue;","hint":"Используй background-color"},{"id":"css-4-3","type":"fill","question":"Вставь свойства для цвета текста и фона","textParts":[".hero { ",": white; ",": black; }"],"fillOptions":["color","background-color","margin","font-size"],"correctFill":["color","background-color"]},{"id":"css-4-4","type":"match","question":"Соедини CSS-свойство и его эффект","pairs":[{"left":"color","right":"Цвет текста"},{"left":"background-color","right":"Цвет фона"},{"left":"border-color","right":"Цвет рамки"}]}]'::jsonb, '[{"id":"css-4-intro-1","speaker":"falstaff","text":"Я Фальстаф. Сейчас разберём теорию урока «Цвета и фон».","emotion":"happy"},{"id":"css-4-intro-2","speaker":"falstaff","text":"color, background, hex","emotion":"think"}]'::jsonb, '[{"id":"css-4-outro-1","speaker":"falstaff","text":"Урок «Цвета и фон» пройден. Молодец!","emotion":"happy"},{"id":"css-4-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Цвета и фон","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"css-4-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"css-4-ma","type":"quiz","question":"Какое свойство меняет фон элемента?","options":["background-color","font-color","bg","fill"],"correctAnswer":"background-color"},"doneLabel":"Готово"},{"id":"css-4-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"css-4-mb","type":"quiz","question":"Повтор: Цвета и фон?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"css-4-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"css-4-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 3) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
INSERT INTO public.lessons (id, level_id, title, description, xp_reward, theory, tasks, story_intro, story_outro, mini_scene, sort_order) VALUES ('css-5', 'css-basics', 'Flexbox', 'display: flex и выравнивание', 30, 'Flexbox выстраивает элементы в ряд или колонку.

Родителю: display: flex; flex-direction: row | column; justify-content — по главной оси; align-items — по поперечной.

Дочерним: flex: 1 — занять свободное место; gap — расстояние между элементами.

Удобен для навбаров, центрирования и адаптивных рядов. После теории — собери макет из flex-контейнера.', '[{"id":"css-5-1","type":"quiz","question":"Какое значение нужно задать display, чтобы включить Flexbox?","options":["flex","block","grid","inline"],"correctAnswer":"flex"},{"id":"css-5-2","type":"debug","question":"Исправь ошибку в flex-правиле","buggyCode":".row { display flex; }","fixedCode":".row { display: flex; }"},{"id":"css-5-3","type":"match","question":"Соедини flex-свойство и его назначение","pairs":[{"left":"justify-content","right":"Выравнивание по главной оси"},{"left":"align-items","right":"Выравнивание по поперечной оси"},{"left":"flex-direction","right":"Направление элементов"}]},{"id":"css-5-4","type":"blocks","question":"Собери базовое flex-правило","blocks":["display: flex;",".container {","}"],"correctOrder":[".container {","display: flex;","}"]}]'::jsonb, '[{"id":"css-5-intro-1","speaker":"falstaff","text":"Я Фальстаф. Сейчас разберём теорию урока «Flexbox».","emotion":"happy"},{"id":"css-5-intro-2","speaker":"falstaff","text":"display: flex и выравнивание","emotion":"think"}]'::jsonb, '[{"id":"css-5-outro-1","speaker":"falstaff","text":"Урок «Flexbox» пройден. Молодец!","emotion":"happy"},{"id":"css-5-outro-2","speaker":"falstaff","text":"Готов к следующему вызову?","emotion":"celebrate","choices":[{"text":"Спасибо, Фальстаф!","response":"Всегда пожалуйста. До следующего урока!"},{"text":"Было сложно!","response":"Сложности закаляют кодера. Ты справился!"}]}]'::jsonb, '{"title":"Мини-мир: Flexbox","subtitle":"Исследуй точки на карте","background":"room","hotspots":[{"id":"css-5-spot-1","label":"А","x":0.25,"y":0.5,"width":0.16,"height":0.14,"task":{"id":"css-5-ma","type":"quiz","question":"Какое значение нужно задать display, чтобы включить Flexbox?","options":["flex","block","grid","inline"],"correctAnswer":"flex"},"doneLabel":"Готово"},{"id":"css-5-spot-2","label":"Б","x":0.5,"y":0.45,"width":0.16,"height":0.14,"task":{"id":"css-5-mb","type":"quiz","question":"Повтор: Flexbox?","options":["Да","Нет"],"correctAnswer":"Да"},"doneLabel":"Готово"},{"id":"css-5-spot-3","label":"В","x":0.75,"y":0.55,"width":0.16,"height":0.14,"task":{"id":"css-5-mc","type":"quiz","question":"Готов дальше?","options":["Да!","Ещё чуть"],"correctAnswer":"Да!"},"doneLabel":"Готово"}]}'::jsonb, 4) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, xp_reward = EXCLUDED.xp_reward, theory = EXCLUDED.theory, tasks = EXCLUDED.tasks, story_intro = EXCLUDED.story_intro, story_outro = EXCLUDED.story_outro, mini_scene = EXCLUDED.mini_scene, sort_order = EXCLUDED.sort_order;
